    investor.last_offset_months = investor.last_offset_months.saturating_add(total_months);
    ctx.accounts.category.tokens_ready_for_claim = ctx
        .accounts
        .category
        .tokens_ready_for_claim
        .saturating_sub(total_tokens);

    Ok(())
}
